Greedy insertion with cheapest feasible assign selection per order, using incremental cost evaluation and fallback to new empty assign if all existing assigns fail.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	assignIndices := make([]int, dispatch.AssignsLen)
	for i := 0; i < dispatch.AssignsLen; i++ {
		assignIndices[i] = i
	}
	for orderIdx := 0; orderIdx < orderCount; orderIdx++ {
		bestAssignIdx := -1
		bestDeltaCost := 0.0
		shipId := total_ship + orderIdx
		ori := oris[orderIdx]
		des := dess[orderIdx]
		inserted := false
		for _, idx := range assignIndices {
			origCost := dispatch.Assigns[idx].Cost
			ok := dispatch.Assigns[idx].AddShip(shipId, ori, des)
			if ok {
				dispatch.Assigns[idx].GenRoute()
				newCost := dispatch.Assigns[idx].Cost
				deltaCost := newCost - origCost
				if deltaCost >= 0 || bestAssignIdx == -1 || deltaCost < bestDeltaCost {
					bestDeltaCost = deltaCost
					bestAssignIdx = idx
				}
				dispatch.Assigns[idx].RemoveShip(shipId)
				dispatch.Assigns[idx].GenRoute()
			}
		}
		if bestAssignIdx != -1 {
			ok := dispatch.Assigns[bestAssignIdx].AddShip(shipId, ori, des)
			if ok {
				dispatch.Assigns[bestAssignIdx].GenRoute()
				inserted = true
			}
		}
		if !inserted {
			if dispatch.AssignsLen < MAXASSIGNS {
				idx := dispatch.AssignsLen
				ok := dispatch.Assigns[idx].AddShip(shipId, ori, des)
				if ok {
					dispatch.Assigns[idx].GenRoute()
					dispatch.AssignsLen++
					inserted = true
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

